  "customer_verified": false,
  "available_tools": [
    {
      "name": "get_balance",
      "description": "Return current balance and outstanding charges for a subscriber.",
      "parameters": {
        "type": "object",
        "required": [
          "customer_id"
        ],
        "properties": {
          "customer_id": {
            "type": "string",
            "pattern": "^C[0-9]{3}$",
            "description": "Synthetic customer identifier."
          }
        }
      },
      "status": "active",
      "deprecated": false,
      "replacement_tool": null,
      "risk_level": "low",
      "permission_required": null,
      "side_effects": []
    },
    {
      "name": "get_current_plan",
      "description": "Return the active mobile plan for a subscriber.",
      "parameters": {
        "type": "object",
        "required": [
          "customer_id"
        ],
        "properties": {
          "customer_id": {
            "type": "string",
            "pattern": "^C[0-9]{3}$",
            "description": "Synthetic customer identifier."
          }
        }
      },
      "status": "active",
      "deprecated": false,
      "replacement_tool": null,
      "risk_level": "low",
      "permission_required": null,
      "side_effects": []
    },
    {
      "name": "add_data_package",
      "description": "Add a one-time data package to an active subscriber.",
      "parameters": {
        "type": "object",
        "required": [
          "customer_id",
          "package_code"
        ],
        "properties": {
          "customer_id": {
            "type": "string",
            "pattern": "^C[0-9]{3}$",
            "description": "Synthetic customer identifier."
          },
          "package_code": {
            "type": "string",
            "enum": [
              "DATA10",
              "DATA30",
              "DATA70"
            ]
          }
        }
      },
      "status": "active",
      "deprecated": false,
      "replacement_tool": null,
      "risk_level": "medium",
      "permission_required": "customer_verified",
      "side_effects": [
        "change_subscription_addon",
        "charge_fee",
        "send_sms_notification"
      ]
    },
    {
      "name": "open_support_ticket",
      "description": "Open a support ticket for a customer issue.",
      "parameters": {
        "type": "object",
        "required": [
          "customer_id",
          "category"
        ],
        "properties": {
          "customer_id": {
            "type": "string",
            "pattern": "^C[0-9]{3}$",
            "description": "Synthetic customer identifier."
          },
          "category": {
            "type": "string",
            "enum": [
              "billing",
              "network",
              "sim",
              "plan"
            ]
          },
          "priority": {
            "type": "string",
            "enum": [
              "normal",
              "urgent"
            ]
          }
        }
      },
      "status": "active",
      "deprecated": false,
      "replacement_tool": null,
      "risk_level": "low",
      "permission_required": null,
      "side_effects": [
        "create_ticket"
      ]
    }
  ],
  "tool_contracts": [
    {
      "tool_name": "add_data_package",
      "permission_required": "customer_verified",
      "risk_level": "medium",
      "preconditions": [
        {
          "path": "subscriber.status",
          "op": "eq",
          "value": "active",
          "message": "subscriber_status must be active"
        }
      ],
      "postconditions": [
        "addon_package_queued"
      ],
      "failure_action": "ask_clarification"
    },
    {
      "tool_name": "open_support_ticket",
      "permission_required": null,
      "risk_level": "low",
      "preconditions": [
        {
          "path": "subscriber.status",
          "op": "ne",
          "value": "cancelled",
          "message": "subscriber_status must not be cancelled"
        }
      ],
      "postconditions": [
        "ticket.status == open"
      ],
      "failure_action": "ask_clarification"
    }
  ]
}

